def validate_identifier(identifier: str, allowed_set: set) -> bool:
    if not identifier:
        return False
    if identifier not in allowed_set:
        return False
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', identifier):
        return False
    return True


def validate_table_name(table_name: str) -> bool:
    return validate_identifier(table_name, ALLOWED_TABLES)


def validate_column_name(table_name: str, column_name: str) -> bool:
    if table_name not in ALLOWED_COLUMNS:
        return False
    return validate_identifier(column_name, ALLOWED_COLUMNS[table_name])


def validate_columns(table_name: str, columns: List[str]) -> bool:
    if not columns:
        return False
    for column in columns:
        if not validate_column_name(table_name, column):
            return False
    return True


def build_where_clause(table_name: str, filters: List[Dict[str, Any]]) -> Tuple[sql.Composable, List[Any]]:
    if not filters:
        return sql.SQL(""), []
    
    conditions = []
    params = []
    
    for filter_item in filters:
        column = filter_item.get('column')
        operator = filter_item.get('operator', 'eq')
        value = filter_item.get('value')
        
        if not validate_column_name(table_name, column):
            raise ValueError(f"Invalid column name: {column}")
        
        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Invalid operator: {operator}")
        
        sql_operator = ALLOWED_OPERATORS[operator]
        
        if operator in ['is_null', 'is_not_null']:
            conditions.append(
                sql.SQL("{} {}").format(
                    sql.Identifier(column),
                    sql.SQL(sql_operator)
                )
            )
        elif operator in ['in', 'not_in']:
            if not isinstance(value, list):
                raise ValueError(f"Value for {operator} must be a list")
            placeholders = sql.SQL(', ').join([sql.Placeholder()] * len(value))
            conditions.append(
                sql.SQL("{} {} ({})").format(
                    sql.Identifier(column),
                    sql.SQL(sql_operator),
                    placeholders
                )
            )
            params.extend(value)
        else:
            conditions.append(
                sql.SQL("{} {} {}").format(
                    sql.Identifier(column),
                    sql.SQL(sql_operator),
                    sql.Placeholder()
                )
            )
            params.append(value)
    
    where_clause = sql.SQL(" WHERE ") + sql.SQL(" AND ").join(conditions)
    return where_clause, params


def build_order_clause(table_name: str, order_by: List[Dict[str, str]]) -> sql.Composable:
    if not order_by:
        return sql.SQL("")
    
    order_parts = []
    for order_item in order_by:
        column = order_item.get('column')
        direction = order_item.get('direction', 'ASC').upper()
        
        if not validate_column_name(table_name, column):
            raise ValueError(f"Invalid column name for ordering: {column}")
        
        if direction not in ALLOWED_ORDER_DIRECTIONS:
            raise ValueError(f"Invalid order direction: {direction}")
        
        order_parts.append(
            sql.SQL("{} {}").format(
                sql.Identifier(column),
                sql.SQL(direction)
            )
        )
    
    return sql.SQL(" ORDER BY ") + sql.SQL(", ").join(order_parts)


def build_group_by_clause(table_name: str, group_by: List[str]) -> sql.Composable:
    if not group_by:
        return sql.SQL("")
    
    for column in group_by:
        if not validate_column_name(table_name, column):
            raise ValueError(f"Invalid column name for grouping: {column}")
    
    group_identifiers = [sql.Identifier(col) for col in group_by]
    return sql.SQL(" GROUP BY ") + sql.SQL(", ").join(group_identifiers)


def build_select_clause(table_name: str, columns: List[str], aggregations: List[Dict[str, str]] = None) -> sql.Composable:
    select_parts = []
    
    for column in columns:
        if not validate_column_name(table_name, column):
            raise ValueError(f"Invalid column name: {column}")
        select_parts.append(sql.Identifier(column))
    
    if aggregations:
        for agg in aggregations:
            func = agg.get('function', '').upper()
            column = agg.get('column')
            alias = agg.get('alias')
            
            if func not in ALLOWED_AGGREGATIONS:
                raise ValueError(f"Invalid aggregation function: {func}")
            
            if column != '*' and not validate_column_name(table_name, column):
                raise ValueError(f"Invalid column name for aggregation: {column}")
            
            if alias and not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', alias):
                raise ValueError(f"Invalid alias: {alias}")
            
            if column == '*':
                agg_expr = sql.SQL("{}(*)").format(sql.SQL(func))
            else:
                agg_expr = sql.SQL("{}({})").format(
                    sql.SQL(func),
                    sql.Identifier(column)
                )
            
            if alias:
                agg_expr = sql.SQL("{} AS {}").format(agg_expr, sql.Identifier(alias))
            
            select_parts.append(agg_expr)
    
    return sql.SQL(", ").join(select_parts)


@app.route('/api/query', methods=['POST'])
def query_data():
    try:
        data = request.get_json()
        
        if not data:
            return jsonify({'error': 'No data provided'}), 400
        
        table_name = data.get('table')
        columns = data.get('columns', [])
        filters = data.get('filters', [])
        order_by = data.get('order_by', [])
        group_by = data.get('group_by', [])
        aggregations = data.get('aggregations', [])
        limit = min(data.get('limit', DEFAULT_LIMIT), MAX_LIMIT)
        offset = data.get('offset', 0)
        
        if not validate_table_name(table_name):
            return jsonify({'error': 'Invalid or unauthorized table name'}), 400
        
        if not columns and not aggregations:
            return jsonify({'error': 'No columns or aggregations specified'}), 400
        
        if columns and not validate_columns(table_name, columns):
            return jsonify({'error': 'Invalid column names'}), 400
        
        if not isinstance(limit, int) or limit < 1:
            return jsonify({'error': 'Invalid limit'}), 400
        
        if not isinstance(offset, int) or offset < 0:
            return jsonify({'error': 'Invalid offset'}), 400
        
        select_clause = build_select_clause(table_name, columns, aggregations)
        where_clause, params = build_where_clause(table_name, filters)
        group_by_clause = build_group_by_clause(table_name, group_by)
        order_clause = build_order_clause(table_name, order_by)
        
        query = sql.SQL("SELECT {} FROM {}{}{}{}").format(
            select_clause,
            sql.Identifier(table_name),
            where_clause,
            group_by_clause,
            order_clause
        )
        
        query = sql.SQL("{} LIMIT {} OFFSET {}").format(
            query,
            sql.Literal(limit),
            sql.Literal(offset)
        )
        
        conn = get_db_connection()
        cursor = conn.cursor(cursor_factory=extras.RealDictCursor)
        
        cursor.execute(query, params)
        results = cursor.fetchall()
        
        cursor.close()
        conn.close()
        
        return jsonify({
            'success': True,
            'data': [dict(row) for row in results],
            'count': len(results)
        }), 200
        
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({'error': 'Database error occurred'}), 500
    except Exception as e:
        return jsonify({'error': 'An unexpected error occurred'}), 500


